#include<bits/stdc++.h>
using namespace std;
long long n,k,a[1000005];
bool check(long long mid){
	mid *= k;
	int i = 0;
	for(;i < n; i++){
//		cout << a[i] << " ";
		if(a[i] <= 0)mid += a[i] - 1;
	}
//	cout << endl ;
	return mid >= 0;
}
int main()
{
//	freopen("ice.in","r",stdin);
//	freopen("ice.out","w",stdout);
	cin >> n >> k;
	for(int i = 0; i < n ; i++){
		cin >> a[i];
	}
	sort(a, a + n);
	long long l = 0, r = 1e13 ;
	while(l < r){
		long long mid = (l + r + 1) / 2;
		for (int i = 0; i < n; i++)a[i] -= mid;
//		cout << l << " " << r << " " << mid << endl;
		if(check(mid))l = mid;
		else r = mid - 1; 
		for (int i = 0; i < n; i++)a[i] += mid;
	}
	cout << l ;
}
